SELECT 
FROM vso_wishlist t
WHERE t.wishlist_id = #{wishlistId}
AND t.user_id = #{userId}
AND t.row_valid = 1

SELECT 
FROM vso_wishlist t
WHERE t.row_valid = 1

    AND t.user_id = #{userId}


    AND t.sale_model = #{saleModel}


    AND t.status = #{status}

ORDER BY t.modify_time DESC

SELECT COUNT(*)
FROM vso_wishlist t
WHERE t.row_valid = 1

    AND t.user_id = #{userId}


    AND t.sale_model = #{saleModel}


    AND t.status = #{status}

SELECT 
FROM vso_wishlist t
WHERE t.user_id = #{userId}
AND t.sale_model_code = #{saleModelCode}
AND t.model_code = #{modelCode}
AND t.variant_code = #{variantCode}
AND t.configuration_code = #{configurationCode}
AND t.option_codes_hash = #{optionCodesHash}
AND t.status = 'ACTIVE'
AND t.row_valid = 1
LIMIT 1

SELECT 
FROM vso_wishlist t
WHERE t.user_id = #{userId}
AND t.sale_model_code = #{saleModelCode}
AND t.model_code = #{modelCode}
AND t.variant_code = #{variantCode}
AND t.configuration_code = #{configurationCode}
AND t.option_codes_hash = #{optionCodesHash}
AND t.wishlist_id != #{excludeWishlistId}
AND t.status = 'ACTIVE'
AND t.row_valid = 1
LIMIT 1
